    const url = cursor 
        ? `${BASE_URL}/getComments?postId=${postId}&limit=${limit}&before=${cursor}` 
        : `${BASE_URL}/getComments?postId=${postId}&limit=${limit}`;
    // ... fetch
}
```

**Backend Service (`server/services/getService.js`, lines 1324-1361):**
```javascript
export const getCommentsService = async(postId, limit, before) => {
    const parsedLimit = parseInt(limit);

    let query = supabase
        .from('comments')
        .select(COMMENT_WITH_USER_SELECT)
        .eq('post_id', postId)
        .is('parent_id', null)
        .order('created_at', {ascending: false})
        .order('id', {ascending: false})
        .limit(parseInt(limit) + 1)  // FETCH +1

    if(before){
        query = query.lt('created_at', before);  // LESS-THAN for cursor
    }

    const {data: comments, error} = await query;

    const hasMore = comments.length > parsedLimit;
    const slicedData = hasMore ? comments.splice(0, parsedLimit) : comments;

    return {comments: slicedData, hasMore: hasMore};
}
```

